traversal_info.sparql:
PREFIX hetio: <https://het.io/schema/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?disease ?diseaseLabel ?description
WHERE {
  ?disease a hetio:Disease .
  ?disease rdfs:label ?diseaseLabel .
  OPTIONAL { ?disease hetio:description ?description . }
  FILTER (REGEX(?diseaseLabel, "Alzheimer", "i") || REGEX(?description, "amyloid-beta|tau|neurofibrillary", "i"))
}
LIMIT 10
